  describe('abort signal', () => {
    it('should stop indexing when abort signal fires', async () => {
      const controller = new AbortController();

      mockGitCommands([
        { match: 'rev-parse', stdout: 'main\n' },
        {
          match: 'log',
          stdout: [
            'sha3|3|third|A|sha2',
            'sha2|2|second|A|sha1',
