import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest';
import * as vscode from 'vscode';
import type { IFileAnalysisResult } from '../../../../src/core/plugins/types/contracts';
import type { IGraphData } from '../../../../src/shared/graph/types';
import { WorkspacePipeline } from '../../../../src/extension/pipeline/service';
import * as pluginModule from '../../../../src/extension/pipeline/plugins/queries';
import * as runModule from '../../../../src/extension/pipeline/analysis/run';
import * as stateModule from '../../../../src/extension/pipeline/analysis/state';
import * as repoMetaModule from '../../../../src/extension/repoSettings/meta';
import * as gitExecModule from '../../../../src/extension/gitHistory/exec';

let workspaceFoldersValue:
  | Array<{ uri: { fsPath: string; path: string }; name: string; index: number }>
  | undefined;

Object.defineProperty(vscode.workspace, 'workspaceFolders', {
  get: () => workspaceFoldersValue,
  configurable: true,
});

function createContext() {
  return {
    subscriptions: [],
    extensionUri: vscode.Uri.file('/test/extension'),
    workspaceState: {
      get: vi.fn(() => undefined),
      update: vi.fn(() => Promise.resolve()),
    },
  };
}

function createGraph(): IGraphData {
  return {
    nodes: [{ id: 'src/index.ts', label: 'index.ts', color: '#93C5FD' }],
    edges: [],
  };
}

describe('WorkspacePipeline delegates', () => {
  beforeEach(() => {
    workspaceFoldersValue = [
      { uri: vscode.Uri.file('/test/workspace'), name: 'workspace', index: 0 },
    ];
    vi.clearAllMocks();
    vi.spyOn(repoMetaModule, 'readCodeGraphyRepoMeta').mockReturnValue(
      repoMetaModule.createDefaultCodeGraphyRepoMeta(),
    );
    vi.spyOn(repoMetaModule, 'writeCodeGraphyRepoMeta').mockImplementation(() => {});
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('delegates analyze through the shared runner with the current workspace root', async () => {
    const context = createContext();
    const analyzer = new WorkspacePipeline(
      context as unknown as vscode.ExtensionContext,
    );
    const signal = new AbortController().signal;
    const disabledPlugins = new Set(['plugin.python']);
    const expectedGraph = createGraph();
    vi.spyOn(gitExecModule, 'execGitCommand').mockResolvedValue('abc123\n');
    const runSpy = vi
      .spyOn(runModule, 'runWorkspacePipelineAnalysis')
      .mockImplementation(
        async (
          source,
          cache,
          config,
          discovery,
          getWorkspaceRoot,
          filterPatterns,
          nextDisabledPlugins,
          nextProgress,
          nextSignal,
        ) => {
          expect(cache).toBe((analyzer as unknown as { _cache: unknown })._cache);
          expect(config).toBe((analyzer as unknown as { _config: unknown })._config);
          expect(discovery).toBe((analyzer as unknown as { _discovery: unknown })._discovery);
          expect(source._lastDiscoveredFiles).toBe(
            (analyzer as unknown as { _lastDiscoveredFiles: unknown })._lastDiscoveredFiles,
          );
          expect(source._lastFileAnalysis).toBe(
            (analyzer as unknown as { _lastFileAnalysis: unknown })._lastFileAnalysis,
          );
          expect(source._lastFileConnections).toBe(
            (analyzer as unknown as { _lastFileConnections: unknown })._lastFileConnections,
          );
          expect(source._lastWorkspaceRoot).toBe('');
          expect(getWorkspaceRoot()).toBe('/test/workspace');
          expect(filterPatterns).toEqual(['**/*.generated.ts']);
          expect(nextDisabledPlugins).toBe(disabledPlugins);
          expect(nextProgress).toBeUndefined();
          expect(nextSignal).toBe(signal);
          return expectedGraph;
        },
      );

    await expect(
      analyzer.analyze(['**/*.generated.ts'], disabledPlugins, signal),
    ).resolves.toEqual(expectedGraph);
    expect(runSpy).toHaveBeenCalledOnce();
    expect(repoMetaModule.writeCodeGraphyRepoMeta).toHaveBeenCalledWith(
      '/test/workspace',
      expect.objectContaining({
        lastIndexedAt: expect.any(String),
        lastIndexedCommit: 'abc123',
        pluginSignature: null,
        settingsSignature: expect.any(String),
      }),
    );
  });

  it('updates cached discovered files when the shared runner writes them back', async () => {
    const analyzer = new WorkspacePipeline(
      createContext() as unknown as vscode.ExtensionContext,
    );
    const discoveredFiles = [
      {
        absolutePath: '/test/workspace/src/index.ts',
        extension: '.ts',
        name: 'index.ts',
        relativePath: 'src/index.ts',
      },
    ];

    vi.spyOn(runModule, 'runWorkspacePipelineAnalysis').mockImplementation(async source => {
      source._lastDiscoveredFiles = discoveredFiles;
      return { nodes: [], edges: [] };
    });

    await analyzer.analyze();

    expect(
      (analyzer as unknown as { _lastDiscoveredFiles: unknown })._lastDiscoveredFiles,
    ).toBe(discoveredFiles);
  });

  it('updates cached file analysis and connections when the shared runner writes them back', async () => {
    const analyzer = new WorkspacePipeline(
      createContext() as unknown as vscode.ExtensionContext,
    );
    const fileAnalysis = new Map<string, IFileAnalysisResult>([
      ['src/index.ts', { filePath: '/test/workspace/src/index.ts', relations: [] }],
    ]);
    const fileConnections = new Map([
      [
        'src/index.ts',
        [
          {
            resolvedPath: '/test/workspace/src/utils.ts',
            specifier: './utils',
            type: 'static' as const,
            sourceId: 'import',
            kind: 'import' as const,
          },
        ],
      ],
    ]);

    vi.spyOn(runModule, 'runWorkspacePipelineAnalysis').mockImplementation(async source => {
      source._lastFileAnalysis = fileAnalysis;
      source._lastFileConnections = fileConnections;
      return { nodes: [], edges: [] };
    });

    await analyzer.analyze();

    expect(
      (analyzer as unknown as { _lastFileAnalysis: unknown })._lastFileAnalysis,
    ).toBe(fileAnalysis);
    expect(
      (analyzer as unknown as { _lastFileConnections: unknown })._lastFileConnections,
    ).toBe(fileConnections);
  });

  it('updates the cached workspace root when the shared runner writes it back', async () => {
    const analyzer = new WorkspacePipeline(
      createContext() as unknown as vscode.ExtensionContext,
    );
    const workspaceRoot = '/test/workspace';

    vi.spyOn(runModule, 'runWorkspacePipelineAnalysis').mockImplementation(async source => {
      source._lastWorkspaceRoot = workspaceRoot;
      return { nodes: [], edges: [] };
    });

    await analyzer.analyze();

    expect(
      (analyzer as unknown as { _lastWorkspaceRoot: unknown })._lastWorkspaceRoot,
    ).toBe(workspaceRoot);
  });

  it('delegates rebuildGraph through the cached rebuild source', () => {
    const analyzer = new WorkspacePipeline(
      createContext() as unknown as vscode.ExtensionContext,
    );
    const disabledPlugins = new Set(['plugin.python']);
    const expectedGraph = createGraph();
    const rebuildSpy = vi
      .spyOn(stateModule, 'rebuildWorkspacePipelineGraphForSource')
      .mockReturnValue(expectedGraph);

    expect(
      analyzer.rebuildGraph(disabledPlugins, false),
    ).toEqual(expectedGraph);
    const [source, nextDisabledPlugins, nextShowOrphans] =
      rebuildSpy.mock.calls[0];
    expect(source._lastFileAnalysis).toBe(
      (analyzer as unknown as { _lastFileAnalysis: unknown })._lastFileAnalysis,
    );
    expect(source._lastFileConnections).toBe(
      (analyzer as unknown as { _lastFileConnections: unknown })._lastFileConnections,
    );
    expect(source._lastWorkspaceRoot).toBe('');
    expect(nextDisabledPlugins).toBe(disabledPlugins);
    expect(nextShowOrphans).toBe(false);
  });

  it('delegates plugin status calculation through the current analyzer state', () => {
    const analyzer = new WorkspacePipeline(
      createContext() as unknown as vscode.ExtensionContext,
    );
    const analyzerPrivate = analyzer as unknown as {
      _lastDiscoveredFiles: Array<{ relativePath: string }>;
      _lastFileConnections: Map<string, never[]>;
      _lastWorkspaceRoot: string;
      _registry: unknown;
    };
    const disabledPlugins = new Set(['plugin.python']);
    const expectedStatuses = [{ id: 'plugin.typescript', status: 'active' }];

    analyzerPrivate._lastDiscoveredFiles = [{ relativePath: 'src/index.ts' }];
    analyzerPrivate._lastFileConnections = new Map([['src/index.ts', []]]);
    analyzerPrivate._lastWorkspaceRoot = '/test/workspace';

    const statusSpy = vi
      .spyOn(pluginModule, 'getWorkspacePipelinePluginStatuses')
      .mockReturnValue(expectedStatuses as never);

    expect(
      analyzer.getPluginStatuses(disabledPlugins),
    ).toEqual(expectedStatuses);
    expect(statusSpy).toHaveBeenCalledWith({
      disabledPlugins,
      discoveredFiles: analyzerPrivate._lastDiscoveredFiles,
      fileConnections: analyzerPrivate._lastFileConnections,
      registry: analyzerPrivate._registry,
    });
  });

  it('delegates plugin name lookup with the live workspace root callback', () => {
    const analyzer = new WorkspacePipeline(
      createContext() as unknown as vscode.ExtensionContext,
    );
    const analyzerPrivate = analyzer as unknown as {
      _lastWorkspaceRoot: string;
      _registry: unknown;
    };

    analyzerPrivate._lastWorkspaceRoot = '';

    const resolveSpy = vi
      .spyOn(pluginModule, 'resolveWorkspacePipelinePluginNameForFile')
      .mockImplementation((relativePath, lastWorkspaceRoot, getWorkspaceRoot, registry) => {
        expect(relativePath).toBe('src/index.ts');
        expect(lastWorkspaceRoot).toBe('');
        expect(getWorkspaceRoot()).toBe('/test/workspace');
        expect(registry).toBe(analyzerPrivate._registry);
        return 'TypeScript';
      });

    expect(analyzer.getPluginNameForFile('src/index.ts')).toBe('TypeScript');
    expect(resolveSpy).toHaveBeenCalledOnce();
  });

  it('delegates cache clearing and replaces the cached analysis state', () => {
    const context = createContext();
    const analyzer = new WorkspacePipeline(
      context as unknown as vscode.ExtensionContext,
    );
    const replacementCache = { version: '1.9.0', files: {} };
    const logSpy = vi.spyOn(console, 'log').mockImplementation(() => {});
    const clearSpy = vi
      .spyOn(stateModule, 'clearWorkspacePipelineCache')
      .mockImplementation((workspaceRoot, logInfo: (message: string) => void) => {
        expect(workspaceRoot).toBe('/test/workspace');
        logInfo('[CodeGraphy] Cache cleared');
        return replacementCache as never;
      });

    analyzer.clearCache();

    expect(clearSpy).toHaveBeenCalledOnce();
    expect(logSpy).toHaveBeenCalledWith('[CodeGraphy] Cache cleared');
    expect((analyzer as unknown as { _cache: unknown })._cache).toBe(replacementCache);
  });
});

import { describe, expect, it, vi } from 'vitest';
import type { IDiscoveredFile } from '../../../../src/core/discovery/contracts';
import type {
  IProjectedConnection,
  IFileAnalysisResult,
} from '../../../../src/core/plugins/types/contracts';
import { DEFAULT_EXCLUDE_PATTERNS } from '../../../../src/extension/config/defaults';
import { formatWorkspacePipelineLimitReachedMessage } from '../../../../src/extension/pipeline/discovery';
import type { IGraphData } from '../../../../src/shared/graph/types';
import { analyzeWorkspaceWithAnalyzer } from '../../../../src/extension/pipeline/analysis/analyze';

function createSource() {
  const emit = vi.fn();
  return {
    _analyzeFiles: vi.fn<
      (files: IDiscoveredFile[], workspaceRoot: string) => Promise<{
        fileAnalysis: Map<string, IFileAnalysisResult>;
        fileConnections: Map<string, IProjectedConnection[]>;
      }>
    >(async () => ({
      fileAnalysis: new Map(),
      fileConnections: new Map(),
    })),
    _buildGraphDataFromAnalysis: vi.fn<() => IGraphData>(() => ({
      nodes: [{ id: 'src/index.ts', label: 'index.ts', color: '#93C5FD' }],
      edges: [{ id: 'src/index.ts->src/utils.ts#import', from: 'src/index.ts', to: 'src/utils.ts' , kind: 'import', sources: [] }],
    } satisfies IGraphData)),
    _buildGraphData: vi.fn<() => IGraphData>(() => ({
      nodes: [{ id: 'src/index.ts', label: 'index.ts', color: '#93C5FD' }],
      edges: [{ id: 'src/index.ts->src/utils.ts#import', from: 'src/index.ts', to: 'src/utils.ts' , kind: 'import', sources: [] }],
    } satisfies IGraphData)),
    _eventBus: { emit },
    _lastDiscoveredFiles: [] as IDiscoveredFile[],
    _lastFileAnalysis: new Map(),
    _lastFileConnections: new Map<string, IProjectedConnection[]>(),
    _lastWorkspaceRoot: '',
    _preAnalyzePlugins: vi.fn(async () => undefined),
    getPluginFilterPatterns: vi.fn(() => ['**/*.generated.ts']),
  };
}

function createDependencies() {
  return {
    discover: vi.fn(async () => ({
      durationMs: 3,
      files: [] as IDiscoveredFile[],
      limitReached: false,
      totalFound: 0,
    })),
    getConfig: vi.fn(() => ({
      include: ['**/*'],
      maxFiles: 25,
      respectGitignore: true,
      showOrphans: true,
    })),
    getWorkspaceRoot: vi.fn<() => string | undefined>(() => '/workspace'),
    logInfo: vi.fn(),
    saveCache: vi.fn(),
    sendProgress: vi.fn(),
    showWarningMessage: vi.fn(),
  };
}

describe('pipeline/analysis/analyze', () => {
  it('returns an empty graph when no workspace root is available', async () => {
    const source = createSource();
    const dependencies = createDependencies();
    dependencies.getWorkspaceRoot.mockReturnValue(undefined);

    await expect(
      analyzeWorkspaceWithAnalyzer(source as never, dependencies as never),
    ).resolves.toEqual({ nodes: [], edges: [] });

    expect(dependencies.logInfo).toHaveBeenCalledWith('[CodeGraphy] No workspace folder open');
    expect(dependencies.discover).not.toHaveBeenCalled();
    expect(source._preAnalyzePlugins).not.toHaveBeenCalled();
    expect(source._analyzeFiles).not.toHaveBeenCalled();
    expect(dependencies.saveCache).not.toHaveBeenCalled();
  });

  it('uses only default and plugin filters when user filters are omitted', async () => {
    const source = createSource();
    const dependencies = createDependencies();

    await analyzeWorkspaceWithAnalyzer(source as never, dependencies as never);

    expect(dependencies.discover).toHaveBeenCalledWith({
      rootPath: '/workspace',
      maxFiles: 25,
      include: ['**/*'],
      exclude: [...DEFAULT_EXCLUDE_PATTERNS, '**/*.generated.ts'],
      respectGitignore: true,
      signal: undefined,
    });
  });

  it('discovers, analyzes, caches, and emits lifecycle events', async () => {
    const source = createSource();
    const dependencies = createDependencies();
    const files = [
      { absolutePath: '/workspace/src/index.ts', relativePath: 'src/index.ts' },
    ] as IDiscoveredFile[];
    const fileAnalysis = new Map<string, IFileAnalysisResult>([
      ['src/index.ts', { filePath: '/workspace/src/index.ts', relations: [] }],
    ]);
    const fileConnections = new Map<string, IProjectedConnection[]>([['src/index.ts', []]]);
    const graphData: IGraphData = {
      nodes: [{ id: 'src/index.ts', label: 'index.ts', color: '#93C5FD' }],
      edges: [{ id: 'src/index.ts->src/utils.ts#import', from: 'src/index.ts', to: 'src/utils.ts' , kind: 'import', sources: [] }],
    };

    dependencies.discover.mockResolvedValue({
      durationMs: 4,
      files,
      limitReached: false,
      totalFound: 1,
    });
    source._analyzeFiles.mockImplementation(
      async (
        _files: IDiscoveredFile[],
        _workspaceRoot: string,
        onProgress?: (progress: { current: number; total: number; filePath: string }) => void,
      ) => {
      onProgress?.({
        current: 1,
        total: 1,
        filePath: '/workspace/src/index.ts',
      });

      return {
        fileAnalysis,
        fileConnections,
      };
      },
    );
    source._buildGraphDataFromAnalysis.mockReturnValue(graphData);

    await expect(
      analyzeWorkspaceWithAnalyzer(
        source as never,
        dependencies as never,
        ['**/*.user.ts'],
        new Set<string>(['plugin.python']),
      ),
    ).resolves.toEqual(graphData);

    expect(dependencies.discover).toHaveBeenCalledOnce();
    expect(source._preAnalyzePlugins).toHaveBeenCalledWith(files, '/workspace', undefined);
    expect(source._analyzeFiles).toHaveBeenCalledWith(
      files,
      '/workspace',
      expect.any(Function),
      undefined,
    );
    expect(source._buildGraphDataFromAnalysis).toHaveBeenCalledWith(
      fileAnalysis,
      '/workspace',
      true,
      new Set<string>(['plugin.python']),
    );
    expect(source._lastDiscoveredFiles).toEqual(files);
    expect(source._lastFileAnalysis).toBe(fileAnalysis);
    expect(source._lastFileConnections).toBe(fileConnections);
    expect(source._lastWorkspaceRoot).toBe('/workspace');
    expect(dependencies.saveCache).toHaveBeenCalledOnce();
    expect(dependencies.logInfo).toHaveBeenCalledWith('[CodeGraphy] Discovered 1 files in 4ms');
    expect(dependencies.logInfo).toHaveBeenCalledWith('[CodeGraphy] Graph built: 1 nodes, 1 edges');
    expect(dependencies.sendProgress).toHaveBeenNthCalledWith(1, {
      phase: 'Analyzing Files',
      current: 0,
      total: 1,
    });
    expect(dependencies.sendProgress).toHaveBeenNthCalledWith(2, {
      phase: 'Analyzing Files',
      current: 1,
      total: 1,
    });
    expect(dependencies.showWarningMessage).not.toHaveBeenCalled();
    expect(source._eventBus.emit).toHaveBeenNthCalledWith(1, 'analysis:started', {
      fileCount: 1,
    });
    expect(source._eventBus.emit).toHaveBeenNthCalledWith(2, 'analysis:completed', {
      graph: {
        nodes: [{ id: 'src/index.ts' }],
        edges: [{ id: 'src/index.ts->src/utils.ts#import' }],
      },
      duration: 0,
    });
  });

  it('shows the discovery warning when the file limit is reached', async () => {
    const source = createSource();
    const dependencies = createDependencies();

    dependencies.discover.mockResolvedValue({
      durationMs: 5,
      files: [] as IDiscoveredFile[],
      limitReached: true,
      totalFound: 27,
    });

    await analyzeWorkspaceWithAnalyzer(source as never, dependencies as never);

    expect(dependencies.showWarningMessage).toHaveBeenCalledWith(
      formatWorkspacePipelineLimitReachedMessage(27, 25),
    );
  });

  it('keeps analyzing when progress reporting and the event bus are unavailable', async () => {
    const source = createSource();
    const dependencies = createDependencies();
    (source as { _eventBus?: { emit: ReturnType<typeof vi.fn> } })._eventBus = undefined;
    (dependencies as { sendProgress?: (progress: { phase: string; current: number; total: number }) => void }).sendProgress = undefined;

    dependencies.discover.mockResolvedValue({
      durationMs: 2,
      files: [] as IDiscoveredFile[],
      limitReached: false,
      totalFound: 0,
    });

    await expect(
      analyzeWorkspaceWithAnalyzer(source as never, dependencies as never),
    ).resolves.toEqual({
      nodes: [{ id: 'src/index.ts', label: 'index.ts', color: '#93C5FD' }],
      edges: [
        {
          id: 'src/index.ts->src/utils.ts#import',
          from: 'src/index.ts',
          to: 'src/utils.ts',
          kind: 'import',
          sources: [],
        },
      ],
    });

    expect(dependencies.showWarningMessage).not.toHaveBeenCalled();
  });
});

import { afterEach, describe, expect, it, vi } from 'vitest';
import type { IDiscoveredFile } from '../../../../src/core/discovery/contracts';
import type { IFileAnalysisResult } from '../../../../src/core/plugins/types/contracts';
import {
  analyzeWorkspacePipelineFiles,
  analyzeWorkspacePipelineSourceFiles,
} from '../../../../src/extension/pipeline/analysis/files';
import * as workspaceFileAnalysisModule from '../../../../src/extension/pipeline/fileAnalysis';

function createDiscoveredFile(relativePath: string): IDiscoveredFile {
  const extensionIndex = relativePath.lastIndexOf('.');
  const slashIndex = relativePath.lastIndexOf('/');

  return {
    absolutePath: `/workspace/${relativePath}`,
    extension: extensionIndex >= 0 ? relativePath.slice(extensionIndex) : '',
    name: slashIndex >= 0 ? relativePath.slice(slashIndex + 1) : relativePath,
    relativePath,
  };
}

describe('pipeline/analysis/files', () => {
  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('logs cache hit and miss counts from workspace file analysis', async () => {
    vi.spyOn(workspaceFileAnalysisModule, 'analyzeWorkspaceFiles').mockResolvedValue({
      cacheHits: 2,
      cacheMisses: 3,
      fileAnalysis: new Map([
        ['src/index.ts', { filePath: '/workspace/src/index.ts', relations: [] }],
      ]),
      fileConnections: new Map([['src/index.ts', []]]),
    });
    const logInfo = vi.fn();

    const result = await analyzeWorkspacePipelineFiles({
      analyzeFile: vi.fn(async (): Promise<IFileAnalysisResult> => ({
        filePath: '/workspace/src/index.ts',
        relations: [],
      })),
      cache: { files: {}, version: '1' } as never,
      files: [],
      getFileStat: vi.fn(async () => null),
      logInfo,
      readContent: vi.fn(async () => ''),
      workspaceRoot: '/workspace',
    });

    expect(result).toEqual({
      cacheHits: 2,
      cacheMisses: 3,
      fileAnalysis: new Map([
        ['src/index.ts', { filePath: '/workspace/src/index.ts', relations: [] }],
      ]),
      fileConnections: new Map([['src/index.ts', []]]),
    });
    expect(logInfo).toHaveBeenCalledWith(
      '[CodeGraphy] Analysis: 2 cache hits, 3 misses',
    );
  });

  it('creates source-backed adapters for file analysis and event emission', async () => {
    const source = {
      _cache: { files: {}, version: '1' },
      _discovery: {
        readContent: vi.fn(async () => "import './utils'"),
      },
      _eventBus: {
        emit: vi.fn(),
      },
      _getFileStat: vi.fn(async () => ({ mtime: 10, size: 5 })),
      _registry: {
        analyzeFileResult: vi.fn(async (): Promise<IFileAnalysisResult> => ({
          filePath: '/workspace/src/index.ts',
          relations: [],
        })),
      },
    };
    const analyzeWorkspaceFilesSpy = vi
      .spyOn(workspaceFileAnalysisModule, 'analyzeWorkspaceFiles')
      .mockResolvedValue({
        cacheHits: 1,
        cacheMisses: 0,
        fileAnalysis: new Map(),
        fileConnections: new Map(),
      });

    await analyzeWorkspacePipelineSourceFiles(
      source as never,
      [
        createDiscoveredFile('src/index.ts'),
      ],
      '/workspace',
      vi.fn(),
    );

    const options = analyzeWorkspaceFilesSpy.mock.calls[0][0];
    await options.analyzeFile('/workspace/src/index.ts', "import './utils'", '/workspace');
    expect(source._registry.analyzeFileResult).toHaveBeenCalledWith(
      '/workspace/src/index.ts',
      "import './utils'",
      '/workspace',
    );
    await options.readContent({
      absolutePath: '/workspace/src/index.ts',
      extension: '.ts',
      name: 'index.ts',
      relativePath: 'src/index.ts',
    });
    expect(source._discovery.readContent).toHaveBeenCalledOnce();
    await options.getFileStat('/workspace/src/index.ts');
    expect(source._getFileStat).toHaveBeenCalledWith('/workspace/src/index.ts');
    options.emitFileProcessed?.({
      filePath: 'src/index.ts',
      connections: [],
    });
    expect(source._eventBus.emit).toHaveBeenCalledWith(
      'analysis:fileProcessed',
      {
        filePath: 'src/index.ts',
        connections: [],
      },
    );
  });

  it('falls back to an empty relation set when the registry returns no analysis result', async () => {
    const source = {
      _cache: { files: {}, version: '1' },
      _discovery: {
        readContent: vi.fn(async () => "import './utils'"),
      },
      _getFileStat: vi.fn(async () => ({ mtime: 10, size: 5 })),
      _registry: {
        analyzeFileResult: vi.fn(async (): Promise<IFileAnalysisResult | null> => null),
      },
    };
